   307→func (s *ExternalAlertmanager) alertToNotifierAlert(alert models.PostableAlert) *Alert {
   308→	// Prometheus alertmanager has stricter rules for annotations/labels than grafana's internal alertmanager, so we sanitize invalid keys.
   309→	return &Alert{
   310→		Labels:       s.options.sanitizeLabelSetFn(alert.Labels),
   311→		Annotations:  s.options.sanitizeLabelSetFn(alert.Annotations),
   312→		StartsAt:     time.Time(alert.StartsAt),
   313→		EndsAt:       time.Time(alert.EndsAt),
   314→		GeneratorURL: alert.GeneratorURL.String(),
   315→	}
   316→}
